"use client";

import { useState, useEffect, useCallback } from "react";
import type { ScheduleConfig, BlockedSlot } from "@/lib/types/database";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Separator } from "@/components/ui/separator";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Textarea } from "@/components/ui/textarea";
import {
  Clock,
  Trash2,
  Plus,
  Save,
  CalendarOff,
  RotateCcw,
  MessageSquare,
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";

const DAYS_OF_WEEK = [
  "Domingo",
  "Segunda",
  "Terca",
  "Quarta",
  "Quinta",
  "Sexta",
  "Sabado",
];

interface DayConfig {
  day_of_week: number;
  is_active: boolean;
  start_time: string;
  end_time: string;
  slot_duration_min: number;
  break_duration_min: number;
  id?: string;
}

const DEFAULT_CONFIG: Omit<DayConfig, "day_of_week"> = {
  is_active: false,
  start_time: "08:00",
  end_time: "18:00",
  slot_duration_min: 50,
  break_duration_min: 10,
};

export default function DisponibilidadePage() {
  const { toast } = useToast();

  const [configs, setConfigs] = useState<DayConfig[]>([]);
  const [blockedSlots, setBlockedSlots] = useState<BlockedSlot[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [addingBlock, setAddingBlock] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  const [returnWindowDays, setReturnWindowDays] = useState(30);
  const [savingReturnWindow, setSavingReturnWindow] = useState(false);

  const DEFAULT_WHATSAPP_TEMPLATE = `Olá, {nome}! Tudo bem?\n\nEquipe do nutricionista Renan Martins passando para confirmar seu horário:\n\n📅 {data} às {horário}\n📍 {modalidade}\n\nSeu horário está reservado. Em caso de imprevisto, informe com antecedência.\n\nSerá um prazer recebê-lo(a).`;
  const [whatsappTemplate, setWhatsappTemplate] = useState(
    DEFAULT_WHATSAPP_TEMPLATE,
  );
  const [savingWhatsappTemplate, setSavingWhatsappTemplate] = useState(false);

  const [newBlock, setNewBlock] = useState({
    date: "",
    start_time: "",
    end_time: "",
    all_day: true,
    reason: "",
  });

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [configRes, blockedRes, settingsRes] = await Promise.all([
        fetch("/api/admin/schedule-config").then((r) => r.ok ? r.json() : { configs: [] }),
        fetch("/api/admin/blocked-slots").then((r) => r.ok ? r.json() : { blocked_slots: [] }),
        fetch("/api/settings").then((r) => r.ok ? r.json() : null).catch(() => null),
      ]);

      if (settingsRes?.return_window_days) {
        setReturnWindowDays(settingsRes.return_window_days);
      }
      if (settingsRes?.whatsapp_template) {
        setWhatsappTemplate(settingsRes.whatsapp_template);
      }

      const existingConfigs = (configRes.configs || []) as ScheduleConfig[];
      const dayConfigs: DayConfig[] = DAYS_OF_WEEK.map((_, index) => {
        const existing = existingConfigs.find((c) => c.day_of_week === index);
        if (existing) {
          return {
            day_of_week: existing.day_of_week,
            is_active: existing.is_active,
            start_time: existing.start_time,
            end_time: existing.end_time,
            slot_duration_min: existing.slot_duration_min,
            break_duration_min: existing.break_duration_min,
            id: existing.id,
          };
        }
        return { ...DEFAULT_CONFIG, day_of_week: index };
      });

      setConfigs(dayConfigs);
      setBlockedSlots((blockedRes.blocked_slots || []) as BlockedSlot[]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  const updateConfig = (index: number, updates: Partial<DayConfig>) => {
    setConfigs((prev) =>
      prev.map((c, i) => (i === index ? { ...c, ...updates } : c)),
    );
  };

  const handleSaveConfigs = async () => {
    setSaving(true);
    try {
      let hasError = false;
      for (const config of configs) {
        const res = await fetch("/api/admin/schedule-config", {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            day_of_week: config.day_of_week,
            start_time: config.start_time,
            end_time: config.end_time,
            slot_duration_min: config.slot_duration_min,
            break_duration_min: config.break_duration_min,
            is_active: config.is_active,
          }),
        });
        if (!res.ok) hasError = true;
      }

      await loadData();

      if (hasError) {
        toast({
          title: "Erro ao salvar",
          description: "Alguns horários não puderam ser salvos.",
          variant: "destructive",
        });
      } else {
        toast({
          title: "Horários salvos",
          description: "Configurações de disponibilidade atualizadas com sucesso.",
        });
      }
    } finally {
      setSaving(false);
    }
  };

  const handleAddBlock = async () => {
    if (!newBlock.date) return;
    setAddingBlock(true);
    try {
      const res = await fetch("/api/admin/blocked-slots", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          date: newBlock.date,
          start_time: newBlock.all_day ? null : newBlock.start_time || null,
          end_time: newBlock.all_day ? null : newBlock.end_time || null,
          all_day: newBlock.all_day,
          reason: newBlock.reason || null,
        }),
      });

      if (!res.ok) {
        const data = await res.json().catch(() => null);
        toast({
          title: "Erro ao adicionar bloqueio",
          description: data?.error || "Não foi possível adicionar.",
          variant: "destructive",
        });
      } else {
        toast({ title: "Bloqueio adicionado", description: "Data bloqueada com sucesso." });
        setNewBlock({ date: "", start_time: "", end_time: "", all_day: true, reason: "" });
      }
      await loadData();
    } finally {
      setAddingBlock(false);
    }
  };

  const handleSaveReturnWindow = async () => {
    setSavingReturnWindow(true);
    try {
      const res = await fetch("/api/settings", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ return_window_days: returnWindowDays }),
      });
      if (res.ok) {
        toast({
          title: "Configuração salva",
          description: "Janela de retorno atualizada com sucesso.",
        });
      } else {
        const data = await res.json().catch(() => null);
        toast({
          title: "Erro ao salvar",
          description: data?.error || "Não foi possível salvar.",
          variant: "destructive",
        });
      }
    } catch {
      toast({
        title: "Erro ao salvar",
        description: "Erro de conexão.",
        variant: "destructive",
      });
    }
    setSavingReturnWindow(false);
  };

  const handleSaveWhatsappTemplate = async () => {
    setSavingWhatsappTemplate(true);
    try {
      const res = await fetch("/api/settings", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ whatsapp_template: whatsappTemplate }),
      });
      if (res.ok) {
        toast({
          title: "Template salvo",
          description: "Mensagem WhatsApp atualizada com sucesso.",
        });
      } else {
        const data = await res.json().catch(() => null);
        toast({
          title: "Erro ao salvar",
          description: data?.error || "Não foi possível salvar.",
          variant: "destructive",
        });
      }
    } catch {
      toast({
        title: "Erro ao salvar",
        description: "Erro de conexão.",
        variant: "destructive",
      });
    }
    setSavingWhatsappTemplate(false);
  };

  const handleDeleteBlock = async (id: string) => {
    setDeletingId(id);
    try {
      const res = await fetch("/api/admin/blocked-slots", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ id }),
      });
      if (!res.ok) {
        const data = await res.json().catch(() => null);
        toast({
          title: "Erro ao remover bloqueio",
          description: data?.error || "Não foi possível remover.",
          variant: "destructive",
        });
      } else {
        toast({ title: "Bloqueio removido", description: "O bloqueio foi removido com sucesso." });
      }
      await loadData();
    } finally {
      setDeletingId(null);
    }
  };

  if (loading) {
    return (
      <div className="p-6 space-y-6">
        <Skeleton className="h-8 w-64" />
        <Skeleton className="h-96 w-full" />
        <Skeleton className="h-64 w-full" />
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-6 space-y-6 max-w-4xl mx-auto">
      <div>
        <h1 className="text-2xl font-bold" data-testid="text-page-title">
          Disponibilidade
        </h1>
        <p className="text-muted-foreground mt-1">
          Configure seus horarios de atendimento e bloqueie datas
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-lg">
            <Clock className="w-5 h-5" />
            Horarios por Dia da Semana
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {configs.map((config, index) => (
            <div key={config.day_of_week}>
              <div className="space-y-3 sm:space-y-0">
                <div className="flex items-center gap-4 flex-wrap">
                  <div className="w-24 shrink-0">
                    <Label
                      className="font-medium"
                      data-testid={`text-day-label-${config.day_of_week}`}
                    >
                      {DAYS_OF_WEEK[config.day_of_week]}
                    </Label>
                  </div>

                  <div className="flex items-center gap-2">
                    <Switch
                      checked={config.is_active}
                      onCheckedChange={(checked) =>
                        updateConfig(index, { is_active: checked })
                      }
                      data-testid={`switch-active-${config.day_of_week}`}
                    />
                    <Label className="text-muted-foreground text-xs">
                      {config.is_active ? "Ativo" : "Inativo"}
                    </Label>
                  </div>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 mt-2 sm:mt-0 sm:ml-28">
                  <div className="flex items-center gap-2">
                    <Label className="text-xs text-muted-foreground whitespace-nowrap">
                      Inicio
                    </Label>
                    <Input
                      type="time"
                      value={config.start_time}
                      onChange={(e) =>
                        updateConfig(index, { start_time: e.target.value })
                      }
                      disabled={!config.is_active}
                      className="w-full sm:w-32"
                      data-testid={`input-start-time-${config.day_of_week}`}
                    />
                  </div>

                  <div className="flex items-center gap-2">
                    <Label className="text-xs text-muted-foreground whitespace-nowrap">
                      Fim
                    </Label>
                    <Input
                      type="time"
                      value={config.end_time}
                      onChange={(e) =>
                        updateConfig(index, { end_time: e.target.value })
                      }
                      disabled={!config.is_active}
                      className="w-full sm:w-32"
                      data-testid={`input-end-time-${config.day_of_week}`}
                    />
                  </div>

                  <div className="flex items-center gap-2">
                    <Label className="text-xs text-muted-foreground whitespace-nowrap">
                      Duracao (min)
                    </Label>
                    <Input
                      type="number"
                      value={config.slot_duration_min}
                      onChange={(e) =>
                        updateConfig(index, {
                          slot_duration_min: parseInt(e.target.value) || 0,
                        })
                      }
                      disabled={!config.is_active}
                      className="w-full sm:w-20"
                      min={10}
                      max={120}
                      data-testid={`input-slot-duration-${config.day_of_week}`}
                    />
                  </div>

                  <div className="flex items-center gap-2">
                    <Label className="text-xs text-muted-foreground whitespace-nowrap">
                      Intervalo (min)
                    </Label>
                    <Input
                      type="number"
                      value={config.break_duration_min}
                      onChange={(e) =>
                        updateConfig(index, {
                          break_duration_min: parseInt(e.target.value) || 0,
                        })
                      }
                      disabled={!config.is_active}
                      className="w-full sm:w-20"
                      min={0}
                      max={60}
                      data-testid={`input-break-duration-${config.day_of_week}`}
                    />
                  </div>
                </div>
              </div>
              {index < configs.length - 1 && <Separator className="mt-4" />}
            </div>
          ))}

          <div className="pt-4">
            <Button
              onClick={handleSaveConfigs}
              disabled={saving}
              data-testid="button-save-schedule"
            >
              <Save className="w-4 h-4" />
              {saving ? "Salvando..." : "Salvar Horarios"}
            </Button>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-lg">
            <CalendarOff className="w-5 h-5" />
            Bloquear Datas/Horarios
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="space-y-4">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 items-end">
              <div className="flex items-center gap-2">
                <Label className="text-sm whitespace-nowrap">Data</Label>
                <Input
                  type="date"
                  value={newBlock.date}
                  onChange={(e) =>
                    setNewBlock((p) => ({ ...p, date: e.target.value }))
                  }
                  className="w-full sm:w-44"
                  data-testid="input-block-date"
                />
              </div>

              <div className="flex items-center gap-2">
                <Switch
                  checked={newBlock.all_day}
                  onCheckedChange={(checked) =>
                    setNewBlock((p) => ({ ...p, all_day: checked }))
                  }
                  data-testid="switch-block-all-day"
                />
                <Label className="text-sm">Dia inteiro</Label>
              </div>

              {!newBlock.all_day && (
                <>
                  <div className="flex items-center gap-2">
                    <Label className="text-xs text-muted-foreground whitespace-nowrap">
                      Inicio
                    </Label>
                    <Input
                      type="time"
                      value={newBlock.start_time}
                      onChange={(e) =>
                        setNewBlock((p) => ({
                          ...p,
                          start_time: e.target.value,
                        }))
                      }
                      className="w-full sm:w-32"
                      data-testid="input-block-start-time"
                    />
                  </div>
                  <div className="flex items-center gap-2">
                    <Label className="text-xs text-muted-foreground whitespace-nowrap">
                      Fim
                    </Label>
                    <Input
                      type="time"
                      value={newBlock.end_time}
                      onChange={(e) =>
                        setNewBlock((p) => ({ ...p, end_time: e.target.value }))
                      }
                      className="w-full sm:w-32"
                      data-testid="input-block-end-time"
                    />
                  </div>
                </>
              )}

              <div className="flex items-center gap-2">
                <Label className="text-sm whitespace-nowrap">Motivo</Label>
                <Input
                  value={newBlock.reason}
                  onChange={(e) =>
                    setNewBlock((p) => ({ ...p, reason: e.target.value }))
                  }
                  placeholder="Ex: Feriado, Ferias..."
                  className="w-full sm:w-48"
                  data-testid="input-block-reason"
                />
              </div>

              <div>
                <Button
                  onClick={handleAddBlock}
                  disabled={addingBlock || !newBlock.date}
                  variant="outline"
                  className="w-full sm:w-auto"
                  data-testid="button-add-block"
                >
                  <Plus className="w-4 h-4" />
                  {addingBlock ? "Adicionando..." : "Adicionar"}
                </Button>
              </div>
            </div>
          </div>

          <Separator />

          <div className="space-y-3">
            <h3 className="text-sm font-medium text-muted-foreground">
              Bloqueios cadastrados
            </h3>
            {blockedSlots.length === 0 ? (
              <p
                className="text-sm text-muted-foreground"
                data-testid="text-no-blocks"
              >
                Nenhum bloqueio cadastrado
              </p>
            ) : (
              <div className="space-y-2">
                {blockedSlots.map((slot) => (
                  <div
                    key={slot.id}
                    className="flex items-center justify-between gap-4 p-3 rounded-md border flex-wrap"
                    data-testid={`blocked-slot-${slot.id}`}
                  >
                    <div className="flex items-center gap-3 flex-wrap">
                      <Badge
                        variant="secondary"
                        data-testid={`badge-block-date-${slot.id}`}
                      >
                        {slot.date}
                      </Badge>
                      {slot.all_day ? (
                        <Badge variant="outline">Dia inteiro</Badge>
                      ) : (
                        <span className="text-sm text-muted-foreground">
                          {slot.start_time} - {slot.end_time}
                        </span>
                      )}
                      {slot.reason && (
                        <span className="text-sm">{slot.reason}</span>
                      )}
                    </div>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => handleDeleteBlock(slot.id)}
                      disabled={deletingId === slot.id}
                      data-testid={`button-delete-block-${slot.id}`}
                    >
                      <Trash2 className="w-4 h-4 text-destructive" />
                    </Button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-lg">
            <RotateCcw className="w-5 h-5" />
            Janela de Retorno
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <p className="text-sm text-muted-foreground">
            Após uma consulta concluída, o paciente pode agendar um retorno
            dentro desta janela de dias. Após esse período, será necessário
            agendar uma consulta regular.
          </p>
          <div className="flex items-center gap-3">
            <Label className="text-sm whitespace-nowrap">
              Dias para retorno
            </Label>
            <Input
              type="number"
              value={returnWindowDays}
              onChange={(e) =>
                setReturnWindowDays(parseInt(e.target.value) || 30)
              }
              min={1}
              max={365}
              className="w-24"
              data-testid="input-return-window-days"
            />
            <span className="text-sm text-muted-foreground">dias</span>
          </div>
          <Button
            onClick={handleSaveReturnWindow}
            disabled={savingReturnWindow}
            data-testid="button-save-return-window"
          >
            <Save className="w-4 h-4" />
            {savingReturnWindow ? "Salvando..." : "Salvar"}
          </Button>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-lg">
            <MessageSquare className="w-5 h-5" />
            Mensagem WhatsApp
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <p className="text-sm text-muted-foreground">
            Personalize a mensagem enviada ao paciente quando uma consulta é
            agendada. Use as variáveis abaixo para inserir dados dinâmicos.
          </p>
          <div className="flex flex-wrap gap-2 text-xs">
            {["{nome}", "{tipo}", "{data}", "{horário}", "{modalidade}"].map(
              (v) => (
                <span
                  key={v}
                  className="bg-muted px-2 py-1 rounded font-mono border"
                >
                  {v}
                </span>
              ),
            )}
          </div>
          <div className="space-y-2">
            <Label className="text-sm">Mensagem</Label>
            <Textarea
              value={whatsappTemplate}
              onChange={(e) => setWhatsappTemplate(e.target.value)}
              rows={4}
              className="resize-none font-mono text-sm"
              placeholder="Olá, {nome}! Sua {tipo} foi agendada para {data} às {horário}."
              data-testid="textarea-whatsapp-template"
            />
          </div>
          <div className="flex items-center gap-3">
            <Button
              onClick={handleSaveWhatsappTemplate}
              disabled={savingWhatsappTemplate}
              data-testid="button-save-whatsapp-template"
            >
              <Save className="w-4 h-4" />
              {savingWhatsappTemplate ? "Salvando..." : "Salvar"}
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setWhatsappTemplate(DEFAULT_WHATSAPP_TEMPLATE)}
              data-testid="button-reset-whatsapp-template"
            >
              Restaurar padrão
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}
